// Service Layer for MFA Management
@Service
public class MfaService {
    @Autowired
    private UserRepository userRepository;
    @Autowired
    private BackupCodeRepository backupCodeRepository;

    public void enableTwoFactorAuthentication(Long userId) {
        User user = userRepository.findById(userId).orElseThrow();
        user.setTwoFactorEnabled(true);
        List<BackupCode> codes = generateRecoveryCodes(10); // Generate 10 recovery codes
        for (BackupCode code : codes) {
            backupCodeRepository.save(code);
        }
        userRepository.save(user);
    }

    public void authenticateUsingBackupCode(Long userId, String backupCode) {
        User user = userRepository.findById(userId).orElseThrow();
        if (user.getTwoFactorEnabled()) {
            BackupCode existingCode = backupCodeRepository.findByUserCodeAndExpiredFalse(user.getId());
            if (existingCode != null && existingCode.getCode().equals(backupCode)) {
                // Successful authentication
                return;
            } else {
                // Backup code is invalid or has expired
                throw new AuthenticationException("Invalid backup code");
            }
        } else {
            // Two-factor authentication not enabled for this user
            throw new AuthenticationException("Two-factor authentication not enabled");
        }
    }

    private List<BackupCode> generateRecoveryCodes(int count) {
        List<BackupCode> codes = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            BackupCode code = new BackupCode();
            code.setCode(generateRandomString(6)); // Generate a random 6-character string
            codes.add(code);
        }
        return codes;
    }

    private String generateRandomString(int length) {
        StringBuilder sb = new StringBuilder(length);
        for (int i = 0; i < length; i++) {
            sb.append((char) (Math.random() * 26 + 'a'));
        }
        return sb.toString();
    }
}

